1	/**
2	 * LayerInfinite MCP Server — li-recommend-tool.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Virtual li_recommend tool. Injected into every tools/list
5	 * response (non-bootstrap modes). When called, returns ranked
6	 * recommendations from the LI scoring engine.
7	 * ══════════════════════════════════════════════════════════════
8	 */
9	
10	import type { EnrichedTool, ScoredAction } from './types.js';
11	import type { LiApiClient, UpstreamCallResult } from './rest-client.js';
12	import { logger } from './logger.js';
13	
14	const log = logger.forTool('li-recommend-tool');
15	
16	const RECOMMEND_TOOL_DEF: Omit<EnrichedTool, 'annotations'> = {
17	  name: 'li_recommend',
18	  description:
19	    'Get LayerInfinite recommendations for the best tool to use for this task type based on historical success data across all agents.',
20	  inputSchema: {
21	    type: 'object',
22	    properties: {
23	      task: {
24	        type: 'string',
25	        description: 'The task type to get recommendations for (e.g., "build_failed", "ci_timeout", "deploy_error")',
26	      },
27	    },
28	    required: ['task'],
29	  },
30	  upstreamName: 'layerinfinite',
31	};
32	
33	/** Create the li_recommend enriched tool entry with annotations. */
34	export function createLiRecommendTool(): EnrichedTool {
35	  return {
36	    ...RECOMMEND_TOOL_DEF,
37	    annotations: { category: 'recommended', ranking: 0 },
38	  };
39	}
40	
41	/** Handle a call to the virtual li_recommend tool. */
42	export async function handleLiRecommend(
43	  liApi: LiApiClient,
44	  taskType: string,
45	  customerId: string,
46	  agentId: string,
47	): Promise<UpstreamCallResult> {
48	  try {
49	    const scores = await liApi.getScores(taskType, customerId, agentId);
50	    const text = formatRecommendations(scores);
51	    return { content: [{ type: 'text', text }] };
52	  } catch (err) {
53	    log.warn('li_recommend failed', {
54	      error: err instanceof Error ? err.message : String(err),
55	    });
56	    return {
57	      content: [
58	        {
59	          type: 'text',
60	          text: 'Unable to fetch recommendations right now. Please try again or select a tool manually.',
61	        },
62	      ],
63	      isError: true,
64	    };
65	  }
66	}
67	
68	function formatRecommendations(scores: ScoredAction[]): string {
69	  if (scores.length === 0) {
70	    return 'No recommendations available yet. Execute a few tasks to build up outcome history.';
71	  }
72	
73	  const ranked = [...scores]
74	    .sort((a, b) => b.compositeScore - a.compositeScore)
75	    .slice(0, 5);
76	
77	  const lines = ['**Top recommended tools:**', ''];
78	
79	  for (let i = 0; i < ranked.length; i++) {
80	    const s = ranked[i];
81	    const icon = trendIcon(s.trendLabel);
82	    const warning = s.successRate < 50 && s.sampleSize >= 5 ? ' ⚠ BELOW THRESHOLD' : '';
83	    lines.push(
84	      `${i + 1}. **${s.actionName}** — ${s.successRate}% success (${s.sampleSize} runs)${icon}${warning}`,
85	    );
86	  }
87	
88	  lines.push('');
89	  lines.push(
90	    ranked.length > 1
91	      ? 'Call a tool by name to execute it. LayerInfinite will automatically reroute in Auto mode when a better tool is available.'
92	      : 'This is the only tool with outcome history for this task type.',
93	  );
94	
95	  return lines.join('\n');
96	}
97	
98	function trendIcon(trendLabel?: string): string {
99	  if (!trendLabel) return '';
100	  switch (trendLabel) {
101	    case 'strongly_improving':
102	    case 'improving':
103	      return ' ↑';
104	    case 'declining':
105	    case 'sharply_declining':
106	      return ' ↓';
107	    default:
108	      return '';
109	  }
110	}
