702	/**
703	 * Insert a single normalized outcome row into fact_outcomes.
704	 * All callers (SDK route + import route) go through this function.
705	 */
706	export async function ingestOutcome(
707	    row: NormalizedOutcomeRow,
708	    customerId: string,
709	    opts: IngestCoreOptions,
710	): Promise<IngestCoreResult> {
711	    // 1. Resolve task name
712	    const taskInferResult = resolveTaskName(row.task_name, row.issue_type);
713	
714	    // Preserve parser-provided mapping metadata when available.
715	    if (
716	        typeof row.task_mapping_confidence === 'number'
717	        && Number.isFinite(row.task_mapping_confidence)
718	        && typeof row.task_mapping_tier === 'string'
719	        && isTaskMappingTier(row.task_mapping_tier)
720	    ) {
721	        taskInferResult.confidence = Math.max(0, Math.min(1, row.task_mapping_confidence));
722	        taskInferResult.tier = row.task_mapping_tier;
723	        if (row.task_name && row.task_name.trim().length > 0) {
724	            taskInferResult.task = row.task_name;
725	        }
726	    }
727	
728	    // 2. Idempotency check
729	    if (row.idempotency_key) {
730	        const existing = await checkIdempotency(row.idempotency_key, customerId);
731	        if (existing) {
732	            const replayRequestedStatus = normalizeExecutionStatus(row.execution_status ?? null);
733	            const replayExecutionStatus: ExecutionStatus = replayRequestedStatus
734	                ?? (row.success ? 'COMPLETED' : 'FAILED');
735	            const replayStatusOrigin: StatusOrigin = normalizeStatusOrigin(row.status_origin)
736	                ?? (replayRequestedStatus ? 'explicit' : 'inferred_from_success');
737	
738	            // Return existing outcome — no duplicate insert
739	            return {
740	                outcomeId: existing,
741	                actionId: '', // Not available for idempotent replays
742	                timestamp: new Date().toISOString(),
743	                ingestionQuality: {
744	                    data_quality: 1.0,
745	                    score_origin: 'provided',
746	                    is_inconsistent: false,
747	                    mapping_tier: 'idempotent_replay',
748	                    mapping_confidence: 1.0,
749	                    inference_confidence: null,
750	                    outcome_class: null,
751	                    execution_status: replayExecutionStatus,
752	                    status_origin: replayStatusOrigin,
753	                },
754	            };
755	        }
756	    }
757	
758	    // 3. Verification — reconstruct VerifierSignal from NormalizedOutcomeRow fields.
759	    // The sync path gets verifier_signal from the SDK body directly (log-outcome.ts:1203).
760	    // The queued path stores it as verifier_source/verifier_value in the NormalizedOutcomeRow.
761	    // Both paths must apply the same hallucination correction logic.
762	    const verifierSignal = row.verifier_source
763	        ? { source: row.verifier_source as any, value: row.verifier_value ?? undefined }
764	        : undefined;
765	    const verification = resolveVerifiedSuccess(row.success, row.outcome_score ?? null, verifierSignal);
766	
767	    const computedOutcomeScoreRaw: number | null =
768	        row.outcome_score !== undefined && row.outcome_score !== null
769	            ? Math.max(0, Math.min(1, row.outcome_score))
770	            : null;
771	
772	    const computedFinalSuccess = verification.verified_success;
773	    const computedFinalOutcomeScore: number | null =
774	        verification.confidence_override !== null
775	            ? verification.confidence_override
776	            : computedOutcomeScoreRaw;
777	
778	    const finalSuccess = opts.precomputed?.finalSuccess ?? computedFinalSuccess;
779	    const finalOutcomeScore = opts.precomputed?.finalOutcomeScore ?? computedFinalOutcomeScore;
780	    const outcomeScoreRaw = opts.precomputed?.outcomeScoreRaw ?? computedOutcomeScoreRaw;
