243	    const taskNames = [
244	        'trust-update',
245	        'context-drift',
246	        'silent-failure',
247	        'counterfactuals',
248	        'sequence',
249	        'latency-spike',
250	        'cache-invalidation',
251	        'predictive-drift',
252	    ];
253	
254	    const criticalTaskFailures: string[] = [];
255	
256	    results.forEach((result, index) => {
257	        if (result.status === 'rejected') {
258	            const taskName = taskNames[index];
259	            const errorMessage = (result.reason as Error)?.message ?? String(result.reason);
260	
261	            console.error(`[orchestrator:${taskName}] failed`, {
262	                error: errorMessage,
263	                outcomeId: params.outcomeId,
264	                agentId: params.agentId,
265	            });
266	
267	            if (taskName === 'trust-update' || taskName === 'counterfactuals') {
268	                criticalTaskFailures.push(
269	                    `${taskName} failed for outcome_id=${params.outcomeId} agent_id=${params.agentId}: ${errorMessage}`
270	                );
271	            }
272	        }
273	    });
274	
275	    if (criticalTaskFailures.length > 0) {
276	        void Promise.resolve(supabase.from('degradation_alert_events').insert({
277	            customer_id: params.customerId,
278	            agent_id: params.agentId,
279	            alert_type: 'orchestrator_failure',
280	            severity: 'critical',
281	            message: criticalTaskFailures.join(' | '),
282	        })).catch(() => { });
283	    }
284	
285	    // Non-blocking: refresh trust cache row for dashboard reads.
286	    // Trust score/status authority is updateAgentTrust() via update_trust_and_audit RPC.
287	    // IMPORT GUARD: skip for imported rows — trust reflects SDK signal only.
288	    if (params.skipTrust !== true) {
289	        refreshLiveTrustCache(params.agentId).catch((err) =>
290	            console.warn('[orchestrator] refreshLiveTrustCache failed:', (err as Error).message)
291	        );
292	    }
293	}
