750	async function detectSilentFailure(
751	    sb: SupabaseClient,
752	    outcome: {
753	        outcome_id: string;
754	        customer_id: string;
755	        agent_id: string;
756	        action_id: string;
757	        action_name: string;
758	        success: boolean;
759	        outcome_score: number | null;
760	        business_outcome: string | null;
761	        error_code: string | null;
762	    }
763	): Promise<void> {
764	    const isSilentFailure =
765	        outcome.success === true && (
766	            // Explicit score signal: low score despite success flag
767	            (outcome.outcome_score !== null && outcome.outcome_score < 0.3) ||
768	            // Implicit signal: business outcome contradicts success flag
769	            (outcome.business_outcome === 'partial' || outcome.business_outcome === 'failed') ||
770	            // Implicit signal: error code present despite success=true
771	            (outcome.error_code != null && outcome.error_code.trim() !== '')
772	        );
773	
774	    if (!isSilentFailure) return;
775	
776	    const since24h = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
777	    const { data: recentAlert } = await sb
778	        .from('degradation_alert_events')
779	        .select('alert_id')
780	        .eq('customer_id', outcome.customer_id)
781	        .eq('action_id', outcome.action_id)
782	        .eq('alert_type', 'degradation')
783	        .gte('detected_at', since24h)
784	        .limit(1);
785	
786	    if (recentAlert && recentAlert.length > 0) return;
787	
788	    await sb.from('degradation_alert_events').insert({
789	        customer_id: outcome.customer_id,
790	        action_id: outcome.action_id,
791	        alert_type: 'degradation',
792	        severity: 'warning',
793	        current_value: outcome.outcome_score,
794	        baseline_value: 1.0,
795	        message: `Silent failure detected on "${outcome.action_name}": success=true but outcome_score=${outcome.outcome_score}. Technical success, business failure. Score will reflect true outcome.`,
796	    });
797	}

1	/**
2	 * LAYERINFINITE — lib/outcome-score-inference.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Production-Grade 3-Layer Outcome Score Inference Engine
5	 *
6	 * Replaces the hardcoded `outcome_score ?? 0.5` fallback with a
7	 * signal-driven inference pipeline when the developer does not
8	 * provide an explicit outcome_score via score_fn.
9	 *
10	 * Architecture:
11	 *   Layer 1 — Hard Signals  (success, error_code, retry_attempt)
12	 *   Layer 2 — Soft Signals  (business_outcome, verifier, cross_event)
13	 *   Layer 3 — Relative Perf (adaptive baseline from action history)
14	 *
15	 * INVARIANTS:
16	 *   - Developer-provided score_fn always wins — inference is NEVER run
17	 *     when outcome_score is explicitly provided (score_origin='provided').
18	 *   - Inference confidence is capped at 0.85 — never as reliable as
19	 *     developer-provided scores.
20	 *   - Import rows skip inference by default; opt-in is available via
21	 *     ingest-core option enableInferenceWhenSkipTrust.
22	 *   - outcome-weighting.ts is NOT changed — inference feeds it
23	 *     automatically via the improved outcome_score values.
24	 * ══════════════════════════════════════════════════════════════
25	 */
26	
27	import { supabase } from './supabase.js';
28	
29	interface BaselineCacheEntry {
30	    value: ActionBaseline | null;
31	    expiresAt: number;
32	}
33	
34	const actionBaselineCache = new Map<string, BaselineCacheEntry>();
35	
36	const BASELINE_CACHE_TTL_MS_DEFAULT = 2 * 60 * 1000;
37	const BASELINE_CACHE_CLEANUP_INTERVAL_MS = 5 * 60 * 1000;
38	const BASELINE_CACHE_MAX_ENTRIES = 5000;
39	
40	function readPositiveInt(value: string | undefined, fallback: number): number {
41	    const parsed = Number.parseInt(value ?? '', 10);
42	    if (!Number.isFinite(parsed) || parsed <= 0) return fallback;
43	    return parsed;
44	}
45	
46	function getBaselineCacheTtlMs(): number {
47	    return readPositiveInt(
48	        process.env.ACTION_BASELINE_CACHE_TTL_MS,
49	        BASELINE_CACHE_TTL_MS_DEFAULT,
50	    );
51	}
52	
53	function baselineCacheKey(agentId: string, actionId: string): string {
54	    return `${agentId}:${actionId}`;
55	}
56	
57	export function invalidateActionBaselineCache(agentId?: string, actionId?: string): void {
58	    if (agentId && actionId) {
59	        actionBaselineCache.delete(baselineCacheKey(agentId, actionId));
60	        return;
61	    }
62	    actionBaselineCache.clear();
