1	import { supabase } from './supabase.js';
2	import crypto from 'node:crypto';
3	
4	export interface DecisionRow {
5	    agent_id: string | null;
6	    context_id: string;
7	    context_hash: string;
8	    ranked_actions: unknown[];
9	    episode_id: string | null;
10	    episode_position: number;
11	}
12	
13	const buffer: (DecisionRow & { _id: string })[] = [];
14	const MAX_BUFFER_SIZE = 50;
15	
16	let failureCount = 0;
17	let circuitOpenUntil = 0;
18	const FAILURE_THRESHOLD = 3;
19	const CIRCUIT_OPEN_MS = 60_000;
20	const FLUSH_INTERVAL_MS = 5000;
21	
22	function toInsertRow(row: DecisionRow & { _id: string }) {
23	    const { _id, ...rest } = row;
24	    const insertRow: Record<string, unknown> = { id: _id, ...rest };
25	
26	    // Compatibility: some live DBs may still carry a non-null/defaulted
27	    // episode_id column shape. Omitting null lets nullable/default semantics
28	    // apply instead of forcing an explicit NULL write.
29	    if (insertRow.episode_id == null) {
30	        delete insertRow.episode_id;
31	    }
32	
33	    return insertRow;
34	}
35	
36	async function upsertDecisionRows(rows: Array<DecisionRow & { _id: string }>): Promise<void> {
37	    const insertRows = rows.map(toInsertRow);
38	    const { error } = await supabase
39	        .from('fact_decisions')
40	        .upsert(insertRows, { onConflict: 'id', ignoreDuplicates: true });
41	    if (error) throw error;
42	}
43	
44	export function bufferDecision(row: DecisionRow): string {
45	    const uuid = crypto.randomUUID();
46	    buffer.push({ ...row, _id: uuid });
47	    if (buffer.length >= MAX_BUFFER_SIZE) {
48	        flushDecisions().catch(() => { });
49	    }
50	    return uuid;
51	}
52	
53	export async function persistDecision(row: DecisionRow): Promise<string | null> {
54	    // fact_decisions.agent_id is required at the DB level.
55	    if (!row.agent_id) {
56	        return null;
57	    }
58	
59	    const uuid = crypto.randomUUID();
60	    const bufferedRow = { ...row, _id: uuid };
61	
62	    try {
63	        await upsertDecisionRows([bufferedRow]);
64	        failureCount = 0;
65	        return uuid;
66	    } catch (err: any) {
67	        // Preserve data for async retry, but do not return an unusable decision_id.
68	        buffer.push(bufferedRow);
69	        failureCount += 1;
70	
71	        if (failureCount >= FAILURE_THRESHOLD) {
72	            circuitOpenUntil = Date.now() + CIRCUIT_OPEN_MS;
73	            console.error('[decision-writer] Circuit OPEN — synchronous decision writes failed 3 times.');
74	        }
75	
76	        console.warn('[decision-writer] Immediate decision persist failed; queued for retry:', err?.message ?? err);
77	        return null;
78	    }
79	}
80	
81	export async function flushDecisions(): Promise<void> {
82	    if (Date.now() < circuitOpenUntil) {
83	        console.warn('[decision-writer] Circuit open — skipping flush');
84	        return;
85	    }
86	
87	    const rows = buffer.splice(0, buffer.length);
88	    if (rows.length === 0) return;
89	
90	    try {
91	        await upsertDecisionRows(rows);
92	        failureCount = 0;
93	    } catch (err: any) {
94	        buffer.unshift(...rows);
95	        failureCount++;
96	        if (failureCount >= FAILURE_THRESHOLD) {
97	            circuitOpenUntil = Date.now() + CIRCUIT_OPEN_MS;
98	            console.error('[decision-writer] Circuit OPEN — 3 consecutive flush failures. DB writes paused for 60s.');
99	        }
100	        throw err;
101	    }
102	}
103	
104	setInterval(() => {
105	    flushDecisions().catch(() => { });
106	}, FLUSH_INTERVAL_MS).unref();
107	
108	process.on('SIGTERM', () => {
109	    flushDecisions().catch(() => { }).finally(() => process.exit(0));
110	});
