503	/**
504	 * Start the durable Postgres queue worker.
505	 * Claims batches via FOR UPDATE SKIP LOCKED, processes each item
506	 * by directly calling ingestOutcome(), and marks succeeded/failed.
507	 *
508	 * This completely eliminates the HTTP loopback architecture and all
509	 * its associated failure modes (auth, rate-limit, Zod re-parse, timeout).
510	 */
511	export function startDurableQueueWorker(): void {
512	    if (durableWorkerTimer) return; // idempotent
513	
514	    let isProcessing = false; // in-flight guard — prevents overlapping poll ticks
515	
516	    console.log(`[durable-queue] Worker started: name=${PG_WORKER_NAME} batch=${PG_WORKER_BATCH_SIZE} poll=${PG_WORKER_POLL_INTERVAL_MS}ms max_attempts=${PG_WORKER_MAX_ATTEMPTS}`);
517	
518	    durableWorkerTimer = setInterval(async () => {
519	        if (isProcessing) return; // previous tick still running
520	        isProcessing = true;
521	        try {
522	            // Hourly cleanup of succeeded rows (replaces pg_cron on free tier)
523	            await maybePurgeSucceeded();
524	
525	            const batch = await claimDurableBatch(PG_WORKER_NAME, PG_WORKER_BATCH_SIZE);
526	            if (batch.length === 0) return;
527	
528	            const results = await Promise.allSettled(
529	                batch.map(async (row) => {
530	                    try {
531	                        await processDurableItem(row);
532	                        await markSucceeded(row.ingress_id);
533	                    } catch (err: unknown) {
534	                        const message = err instanceof Error ? err.message : String(err);
535	                        await markFailed(row.ingress_id, message, row.attempts, row.max_attempts || PG_WORKER_MAX_ATTEMPTS);
536	                    }
537	                }),
538	            );
539	
540	            // Log batch summary
541	            const succeeded = results.filter(r => r.status === 'fulfilled').length;
542	            const failed = results.length - succeeded;
543	            if (failed > 0) {
544	                console.warn(`[durable-queue] Batch: ${succeeded} succeeded, ${failed} failed`);
545	            }
546	        } catch (err: unknown) {
547	            console.error('[durable-queue] Worker poll error:', err instanceof Error ? err.message : String(err));
548	        } finally {
549	            isProcessing = false;
550	        }
551	    }, PG_WORKER_POLL_INTERVAL_MS);
552	
553	    // Don't prevent Node.js from exiting
554	    if (durableWorkerTimer && typeof durableWorkerTimer === 'object' && 'unref' in durableWorkerTimer) {
555	        (durableWorkerTimer as any).unref();
556	    }
557	}
