1	/**
2	 * Layerinfinite — lib/context-embed.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Context embedding: generate vectors + cosine similarity.
5	 *
6	 * Provider switching via EMBEDDING_PROVIDER env var:
7	 *   'supabase' (default) → Supabase AI gte-small
8	 *   'openai'             → text-embedding-3-small
9	 *
10	 * FALLBACK RULE: If embedding generation fails for ANY reason,
11	 * return null — scoring treats null context_match as 1.0
12	 * (exact match assumed). Never throw, never 500.
13	 * ══════════════════════════════════════════════════════════════
14	 */
15	
16	import { createHash } from 'node:crypto';
17	import { supabase } from './supabase.js';
18	
19	const EMBEDDING_PROVIDER = process.env.EMBEDDING_PROVIDER ?? 'supabase';
20	const OPENAI_API_KEY = process.env.OPENAI_API_KEY ?? '';
21	const EXPECTED_CONTEXT_VECTOR_DIMENSION = Number(
22	    process.env.CONTEXT_VECTOR_DIMENSION ?? '384',
23	);
24	// SIMILARITY_THRESHOLD: cosine similarity floor for context matching.
25	// Below this value, findClosestContext returns null ->
26	// scoring treats as exact match (1.0 penalty applied).
27	//
28	// Calibration (gte-small model, 384-dim):
29	//   > 0.85 -> near-identical phrasing
30	//   0.70-0.85 -> strongly related contexts
31	//   0.60-0.70 -> moderately related (current threshold - permissive)
32	//   < 0.60 -> loosely related or unrelated
33	//
34	// At 0.6, false positives (wrong context matched) are more likely than
35	// at 0.75. Increase to 0.75 if context mismatches appear in scoring logs.
36	const SIMILARITY_THRESHOLD = 0.6;
37	
38	// Versioning: stamp every stored vector with its origin model + version
39	const CURRENT_EMBEDDING_MODEL = EMBEDDING_PROVIDER === 'openai'
40	    ? 'text-embedding-3-small'
41	    : 'gte-small';
42	const CURRENT_EMBEDDING_VERSION = process.env.EMBEDDING_VERSION ?? '2024-01-01';
43	const CURRENT_EMBEDDING_SCHEMA_VERSION = 2;
44	const CONTEXT_EMBEDDING_CACHE_TTL_MS = 10 * 60 * 1000;
45	const MAX_RAW_CONTEXT_EMBED_FIELDS = 20;
46	const MAX_RAW_CONTEXT_EMBED_CHARS = 512;
47	
48	const contextEmbeddingReadyUntil = new Map<string, number>();
49	const contextEmbeddingInFlight = new Map<string, Promise<boolean>>();
50	
51	// ── Generate embedding ───────────────────────────────────────
52	/**
53	 * Generates a provider vector from context text.
54	 * contextText = "payment_failed enterprise production"
55	 * Returns null on failure (never throws).
56	 */
57	export async function generateEmbedding(contextText: string): Promise<number[] | null> {
58	    try {
59	        const embedding = EMBEDDING_PROVIDER === 'openai'
60	            ? await generateOpenAIEmbedding(contextText)
61	            : await generateSupabaseEmbedding(contextText);
62	
63	        if (!embedding) return null;
64	
65	        if (embedding.length !== EXPECTED_CONTEXT_VECTOR_DIMENSION) {
66	            console.warn(
67	                `[context-embed] Embedding dimension mismatch: got=${embedding.length}, ` +
68	                `expected=${EXPECTED_CONTEXT_VECTOR_DIMENSION}. Dropping vector.`
69	            );
70	            return null;
71	        }
72	
73	        return embedding;
74	    } catch (err: any) {
75	        console.warn(`[context-embed] Embedding unavailable — using exact match fallback. Error: ${err.message}`);
76	        return null;
77	    }
78	}
79	
80	async function generateSupabaseEmbedding(text: string): Promise<number[] | null> {
81	    try {
82	        // Use Supabase AI inference endpoint (gte-small model, free, no API key needed)
83	        const supabaseUrl = process.env.SUPABASE_URL;
84	        const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
85	
86	        if (!supabaseUrl || !serviceKey) {
87	            console.warn('[context-embed] SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY not set');
88	            return null;
89	        }
90	
91	        // 5s timeout: Supabase AI endpoint cold-starts can hang for 30s+.
92	        // On abort, falls through to embed_text SQL RPC fallback below.
93	        const controller = new AbortController();
94	        const timeoutId = setTimeout(() => controller.abort(), 5000);
95	        let response: Response;
96	        try {
97	            response = await fetch(`${supabaseUrl}/functions/v1/embedding`, {
98	                method: 'POST',
99	                headers: {
100	                    'Authorization': `Bearer ${serviceKey}`,
101	                    'Content-Type': 'application/json',
102	                },
103	                body: JSON.stringify({ input: text, model: 'gte-small' }),
104	                signal: controller.signal,
105	            });
106	        } finally {
107	            clearTimeout(timeoutId);
108	        }
109	
110	        if (!response.ok) {
111	            // Fallback: try Supabase's built-in SQL embedding via pg function
112	            const { data, error } = await supabase.rpc('embed_text', { input_text: text });
113	            if (error || !data) {
114	                console.warn('[context-embed] Supabase embedding fallback failed:', error?.message ?? 'no data');
115	                return null;
116	            }
117	            return data as number[];
118	        }
119	
120	        const json = await response.json() as any;
121	        if (json?.embedding) return json.embedding as number[];
122	        if (json?.data?.[0]?.embedding) return json.data[0].embedding as number[];
123	
124	        console.warn('[context-embed] Supabase embedding: unexpected response format');
125	        return null;
126	    } catch (err: any) {
127	        console.warn('[context-embed] Supabase embedding error:', err.message);
128	        return null;
129	    }
130	}
