165	// ── Embedding metadata helpers ───────────────────────────────
166	/**
167	 * Returns metadata fields to stamp alongside a stored vector.
168	 * Call at write time whenever inserting/upserting a context_vector.
169	 */
170	export function embeddingVersionMeta(vector: number[], sourceText: string) {
171	    return {
172	        source_text: sourceText,
173	        source_text_hash: createHash('sha256').update(sourceText).digest('hex'),
174	        embedding_model: CURRENT_EMBEDDING_MODEL,
175	        embedding_version: CURRENT_EMBEDDING_VERSION,
176	        embedding_dimension: vector.length,
177	        embedding_schema_version: CURRENT_EMBEDDING_SCHEMA_VERSION,
178	    };
179	}
180	
181	// ── Cosine similarity ────────────────────────────────────────
182	/**
183	 * Standard cosine similarity: dot(a,b) / (|a| × |b|)
184	 * Returns 0.0 to 1.0. Pure function — no async, no DB.
185	 * Throws explicitly on dimension mismatch (not a silent wrong answer).
186	 */
187	export function cosineSimilarity(a: number[], b: number[]): number {
188	    if (a.length !== b.length) {
189	        throw new Error(
190	            `[context-embed] Dimension mismatch in cosineSimilarity: a.length=${a.length}, b.length=${b.length}. ` +
191	            'Vectors from different embedding models cannot be compared.'
192	        );
193	    }
194	    if (a.length === 0) return 0;
195	
196	    let dotProduct = 0;
197	    let normA = 0;
198	    let normB = 0;
199	
200	    for (let i = 0; i < a.length; i++) {
201	        dotProduct += a[i] * b[i];
202	        normA += a[i] * a[i];
203	        normB += b[i] * b[i];
204	    }
205	
206	    const magnitude = Math.sqrt(normA) * Math.sqrt(normB);
207	    if (magnitude === 0) return 0;
208	
209	    return Math.max(0, Math.min(1, dotProduct / magnitude));
210	}
211	
212	// ── Find closest context ─────────────────────────────────────
213	/**
214	 * Finds the context with the highest cosine similarity to the
215	 * given embedding. Returns { context_id, similarity } if above
216	 * threshold (0.6), else null.
217	 */
218	export async function findClosestContext(
219	    embedding: number[],
220	    customerId: string,
221	    options: { environment?: string | null } = {}
222	): Promise<{ context_id: string; similarity: number } | null> {
223	    if (embedding.length !== EXPECTED_CONTEXT_VECTOR_DIMENSION && process.env.NODE_ENV !== 'test') {
224	        console.warn(
225	            `[context-embed] findClosestContext skipped due to dimension mismatch: ` +
226	            `query=${embedding.length}, expected=${EXPECTED_CONTEXT_VECTOR_DIMENSION}`
227	        );
228	        return null;
229	    }
230	
231	    const environmentFilter = typeof options.environment === 'string'
232	        ? options.environment.trim().toLowerCase()
233	        : '';
234	
235	    try {
236	        const { data, error } = await supabase.rpc('match_context_vector', {
237	            query_vector: embedding,
238	            p_customer_id: customerId,
239	            p_model: CURRENT_EMBEDDING_MODEL,
240	            p_threshold: SIMILARITY_THRESHOLD,
241	            p_limit: 1,
242	            p_schema_version: CURRENT_EMBEDDING_SCHEMA_VERSION,
243	        });
244	
245	        if (error) {
246	            // RPC not available — fall back to TypeScript scan scoped to customer
247	            console.warn(
248	                '[context-embed] match_context_vector RPC unavailable, ' +
249	                'falling back to in-memory scan:',
250	                error.message
251	            );
252	            return await findClosestContextFallback(
253	                embedding,
254	                customerId,
255	                environmentFilter || undefined
256	            );
257	        }
258	
259	        if (!data || data.length === 0) return null;
260	
261	        const best = data[0] as { context_id: string; similarity: number };
262	
263	        if (environmentFilter) {
264	            const { data: matchedContext, error: contextError } = await supabase
265	                .from('dim_contexts')
266	                .select('environment')
267	                .eq('customer_id', customerId)
268	                .eq('context_id', best.context_id)
269	                .maybeSingle();
270	
271	            if (contextError || !matchedContext) {
272	                return await findClosestContextFallback(embedding, customerId, environmentFilter);
273	            }
274	
275	            const matchedEnvironment = String((matchedContext as any).environment ?? '').trim().toLowerCase();
276	            if (matchedEnvironment !== environmentFilter) {
277	                return await findClosestContextFallback(embedding, customerId, environmentFilter);
278	            }
279	        }
280	
281	        return best.similarity >= SIMILARITY_THRESHOLD ? best : null;
282	    } catch (err: any) {
283	        console.warn('[context-embed] findClosestContext error:', err.message);
284	        return null;
285	    }
286	}
287	
288	// FALLBACK: used when match_context_vector RPC is unavailable.
289	// Customer-scoped but O(n/customers) — acceptable for dev/small datasets.
290	// In production with pgvector RPC deployed, this path should not be hit.
291	async function findClosestContextFallback(
292	    embedding: number[],
293	    customerId: string,
294	    environment?: string
295	): Promise<{ context_id: string; similarity: number } | null> {
296	    let query = supabase
297	        .from('dim_contexts')
298	        .select('context_id, context_vector, embedding_model, source_text, embedding_schema_version')
299	        .eq('customer_id', customerId)
300	        .eq('embedding_schema_version', CURRENT_EMBEDDING_SCHEMA_VERSION)
301	        .not('context_vector', 'is', null);
302	
303	    if (environment) {
304	        query = query.eq('environment', environment);
305	    }
306	
307	    const { data, error } = await query;
308	
309	    if (error || !data || data.length === 0) {
310	        return null;
311	    }
312	
313	    let bestMatch: { context_id: string; similarity: number } | null = null;
314	
315	    for (const row of data) {
316	        if (row.context_vector === null || row.context_vector === undefined) continue;
317	
318	        // Skip vectors from incompatible embedding models to avoid meaningless scores.
319	        // Null embedding_model means legacy row (pre-migration 056) — allow through conservatively.
320	        if (row.embedding_model && row.embedding_model !== CURRENT_EMBEDDING_MODEL) {
321	            console.warn(
322	                `[context-embed] Skipping context ${row.context_id}: model mismatch ` +
323	                `(stored=${row.embedding_model}, current=${CURRENT_EMBEDDING_MODEL}). ` +
324	                'Run batch re-embedding to migrate.'
325	            );
326	            continue;
327	        }
328	
329	        const storedVec = typeof row.context_vector === 'string'
330	            ? parseVector(row.context_vector)
331	            : (row.context_vector as number[]);
332	
333	        if (!storedVec) {
334	            console.warn(`[context-embed] Skipping context ${row.context_id}: failed to parse stored vector string.`);
335	            continue;
336	        }
337	        if (storedVec.length === 0) continue;
338	
339	        // Dimension safety check before computing similarity
340	        if (storedVec.length !== embedding.length) {
341	            console.warn(
342	                `[context-embed] Skipping context ${row.context_id}: dimension mismatch ` +
343	                `(stored=${storedVec.length}, query=${embedding.length})`
344	            );
345	            continue;
346	        }
347	
348	        const sim = cosineSimilarity(embedding, storedVec);
349	
350	        if (sim > SIMILARITY_THRESHOLD && (!bestMatch || sim > bestMatch.similarity)) {
351	            bestMatch = { context_id: row.context_id, similarity: sim };
352	        }
353	    }
354	
355	    return bestMatch;
356	}
357	
358	/**
359	 * Parse pgvector string format "[0.1,0.2,0.3]" → number[]
360	 */
361	function parseVector(v: string): number[] | null {
362	    try {
363	        const clean = v.replace(/[\[\]]/g, '').trim();
364	        if (!clean) return null;
365	        const parsed = clean.split(',').map(Number);
366	        if (parsed.some(isNaN)) return null;
367	        return parsed;
368	    } catch {
369	        return null;
370	    }
371	}
372	
373	function flattenRawContextForEmbedding(rawContext?: Record<string, unknown>): string {
374	    if (!rawContext || typeof rawContext !== 'object') return '';
375	
376	    const parts: string[] = [];
377	    const entries = Object.entries(rawContext)
378	        .sort(([a], [b]) => a.localeCompare(b))
379	        .slice(0, MAX_RAW_CONTEXT_EMBED_FIELDS);
380	
381	    for (const [key, value] of entries) {
382	        if (value === null || value === undefined) continue;
383	
384	        let normalized = '';
385	        if (typeof value === 'string') {
386	            normalized = value.trim();
387	        } else if (typeof value === 'number' || typeof value === 'boolean') {
388	            normalized = String(value);
389	        } else {
390	            try {
391	                normalized = JSON.stringify(value);
392	            } catch {
393	                normalized = '';
394	            }
395	        }
396	
397	        if (!normalized) continue;
398	        parts.push(`${key}:${normalized}`);
399	    }
400	
401	    return parts.join(' ').slice(0, MAX_RAW_CONTEXT_EMBED_CHARS);
402	}
403	
404	/**
405	 * Build context text from components for embedding.
406	 */
407	export function buildContextText(
408	    issueType: string,
409	    customerTier?: string,
410	    environment?: string,
411	    rawContext?: Record<string, unknown>
412	): string {
413	    const rawContextText = flattenRawContextForEmbedding(rawContext);
414	    return [issueType, customerTier, environment, rawContextText]
415	        .filter(Boolean)
416	        .join(' ')
417	        .trim();
418	}
