1	/**
2	 * LayerInfinite API — lib/confidence-thresholds.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Per-agent per-task confidence thresholds loaded from
5	 * dim_agents.config JSONB.
6	 *
7	 * Each agent's config may specify thresholds per task_type:
8	 *   {
9	 *     "confidence_thresholds": {
10	 *       "build_failed": {
11	 *         "minimum_success_rate": 0.6,
12	 *         "minimum_sample_size": 10,
13	 *         "fallback_behavior": "warn"
14	 *       }
15	 *     }
16	 *   }
17	 *
18	 * If no per-task threshold exists, the agent-level default applies.
19	 * If no agent-level default exists, the global defaults apply.
20	 *
21	 * Fallback behaviors:
22	 *   - "omit":    Exclude actions below threshold from enrichment
23	 *   - "warn":    Include but annotate with a warning
24	 *   - "allow":   Include without restriction (bypass thresholds)
