30	// ── Types ──────────────────────────────────────────────────────
31	
32	export type FallbackBehavior = 'omit' | 'warn' | 'allow';
33	
34	export interface TaskConfidenceThreshold {
35	  minimum_success_rate: number;
36	  minimum_sample_size: number;
37	  fallback_behavior: FallbackBehavior;
38	}
39	
40	export interface AgentConfidenceConfig {
41	  /** Per-task-type overrides. */
42	  thresholds: Map<string, TaskConfidenceThreshold>;
43	  /** Agent-level defaults. */
44	  defaults: TaskConfidenceThreshold;
45	}
46	
47	// ── Global defaults ────────────────────────────────────────────
48	
49	const GLOBAL_DEFAULTS: TaskConfidenceThreshold = {
50	  minimum_success_rate: 0.0,
51	  minimum_sample_size: 1,
52	  fallback_behavior: 'allow',
53	};
54	
55	// ── Cache ──────────────────────────────────────────────────────
56	
57	interface CacheEntry {
58	  config: AgentConfidenceConfig;
59	  expiresAt: number;
60	}
61	
62	const configCache = new Map<string, CacheEntry>();
63	const CONFIG_TTL_MS = 5 * 60 * 1000;
64	
65	function cacheKey(customerId: string, agentId: string): string {
66	  return `${customerId}:${agentId}`;
67	}
68	
69	// ── Public API ─────────────────────────────────────────────────
70	
71	/**
72	 * Load confidence thresholds for an agent.
73	 * Returns a merged config: per-task overrides + agent defaults + global defaults.
74	 */
75	export async function getConfidenceConfig(
76	  customerId: string,
77	  agentId: string,
78	): Promise<AgentConfidenceConfig> {
79	  const key = cacheKey(customerId, agentId);
80	  const cached = configCache.get(key);
81	  if (cached && cached.expiresAt > Date.now()) {
82	    return cached.config;
83	  }
84	
85	  try {
86	    const { data, error } = await supabase
87	      .from('dim_agents')
88	      .select('config')
89	      .eq('agent_id', agentId)
90	      .eq('customer_id', customerId)
91	      .maybeSingle();
92	
93	    const rawConfig = (data?.config as Record<string, unknown>) ?? {};
94	    const ctConfig = rawConfig.confidence_thresholds as Record<string, Record<string, unknown>> | undefined;
95	
96	    // Parse agent-level defaults
97	    const agentDefaults = ctConfig?.['*'] as Record<string, unknown> | undefined;
98	    const defaults: TaskConfidenceThreshold = {
99	      minimum_success_rate: (agentDefaults?.minimum_success_rate as number)
100	        ?? GLOBAL_DEFAULTS.minimum_success_rate,
101	      minimum_sample_size: (agentDefaults?.minimum_sample_size as number)
102	        ?? GLOBAL_DEFAULTS.minimum_sample_size,
103	      fallback_behavior: normalizeFallback(agentDefaults?.fallback_behavior)
104	        ?? GLOBAL_DEFAULTS.fallback_behavior,
105	    };
106	
107	    // Parse per-task overrides
108	    const thresholds = new Map<string, TaskConfidenceThreshold>();
109	    if (ctConfig) {
110	      for (const [taskType, raw] of Object.entries(ctConfig)) {
111	        if (taskType === '*') continue;
112	        thresholds.set(taskType, {
113	          minimum_success_rate: (raw.minimum_success_rate as number) ?? defaults.minimum_success_rate,
114	          minimum_sample_size: (raw.minimum_sample_size as number) ?? defaults.minimum_sample_size,
115	          fallback_behavior: normalizeFallback(raw.fallback_behavior) ?? defaults.fallback_behavior,
116	        });
117	      }
118	    }
119	
120	    const config: AgentConfidenceConfig = { thresholds, defaults };
121	
122	    configCache.set(key, { config, expiresAt: Date.now() + CONFIG_TTL_MS });
123	    return config;
124	  } catch {
125	    return { thresholds: new Map(), defaults: { ...GLOBAL_DEFAULTS } };
126	  }
127	}
