142	/**
143	 * Check if an action passes confidence thresholds.
144	 * Returns { passed, behavior, reason? }.
145	 */
146	export function checkThreshold(
147	  threshold: TaskConfidenceThreshold,
148	  successRate: number,
149	  sampleSize: number,
150	): { passed: boolean; behavior: FallbackBehavior; reason?: string } {
151	  if (sampleSize < threshold.minimum_sample_size) {
152	    return {
153	      passed: false,
154	      behavior: threshold.fallback_behavior,
155	      reason: `Sample size ${sampleSize} < minimum ${threshold.minimum_sample_size}`,
156	    };
157	  }
158	
159	  if (successRate < threshold.minimum_success_rate) {
160	    return {
161	      passed: false,
162	      behavior: threshold.fallback_behavior,
163	      reason: `Success rate ${(successRate * 100).toFixed(0)}% < minimum ${(threshold.minimum_success_rate * 100).toFixed(0)}%`,
164	    };
165	  }
166	
167	  return { passed: true, behavior: 'allow' };
168	}
169	
170	/**
171	 * Apply thresholds to a list of scored actions.
172	 *
173	 * Returns the filtered/enriched list based on fallback behaviors:
174	 *   - "allow": no filtering
175	 *   - "warn": actions below threshold get a warning annotation
176	 *   - "omit": actions below threshold are removed
177	 */
178	export function applyThresholds(
179	  actions: Array<{
180	    action_id: string;
181	    action_name: string;
182	    composite_score: number;
183	    total_attempts: number;
184	    [key: string]: unknown;
185	  }>,
186	  threshold: TaskConfidenceThreshold,
187	): Array<{
188	  action_id: string;
189	  action_name: string;
190	  composite_score: number;
191	  total_attempts: number;
192	  threshold_warning?: string;
193	  [key: string]: unknown;
194	}> {
195	  if (threshold.fallback_behavior === 'allow') {
196	    return actions;
197	  }
198	
199	  return actions
200	    .map((action) => {
201	      const result = checkThreshold(
202	        threshold,
203	        action.composite_score,
204	        action.total_attempts,
205	      );
206	
207	      if (result.passed) return action;
208	
209	      if (threshold.fallback_behavior === 'omit') {
210	        return null; // filtered out below
211	      }
212	
213	      if (threshold.fallback_behavior === 'warn') {
214	        return {
215	          ...action,
216	          composite_score: Math.round(action.composite_score * 10000) / 10000,
217	          threshold_warning: result.reason,
218	        };
219	      }
220	
221	      return action;
222	    })
223	    .filter((a): a is NonNullable<typeof a> => a !== null);
224	}
225	
226	/** Invalidate cached config for an agent. */
227	export function invalidateThresholdConfig(customerId: string, agentId: string): void {
228	  configCache.delete(cacheKey(customerId, agentId));
229	}
