1	/**
2	 * Layerinfinite — middleware/user-auth.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Human user authentication middleware (Supabase JWT).
5	 *
6	 * Verifies the Supabase access token via supabase.auth.getUser().
7	 * Looks up user_profiles to resolve customer_id.
8	 * Sets: user_id, customer_id on the Hono context.
9	 *
10	 * This is SEPARATE from api/middleware/auth.ts (agent API key auth).
11	 * ══════════════════════════════════════════════════════════════
12	 */
13	
14	import { Context, Next } from 'hono';
15	import { createClient } from '@supabase/supabase-js';
16	import { supabase } from '../lib/supabase.js';
17	
18	const SUPABASE_URL = process.env.SUPABASE_URL!;
19	const SUPABASE_ANON_KEY = process.env.SUPABASE_ANON_KEY!;
20	
21	function randomHex(bytes: number): string {
22	    const buf = new Uint8Array(bytes);
23	    crypto.getRandomValues(buf);
24	    return Array.from(buf).map(b => b.toString(16).padStart(2, '0')).join('');
25	}
26	
27	async function provisionMissingProfile(user: { id: string; email?: string | null; user_metadata?: any }) {
28	    const email = user.email ?? `${user.id}@unknown.local`;
29	    const companyName = typeof user.user_metadata?.company_name === 'string' && user.user_metadata.company_name.trim()
30	        ? user.user_metadata.company_name.trim()
31	        : email;
32	
33	    const { data: customer, error: customerError } = await supabase
34	        .from('dim_customers')
35	        .insert({
36	            company_name: companyName,
37	            tier: 'starter',
38	            api_key_hash: randomHex(32),
39	            created_at: new Date().toISOString(),
40	        })
41	        .select('customer_id')
42	        .single();
43	
44	    if (customerError || !customer) {
45	        return { ok: false, reason: customerError?.message ?? 'Failed to create customer row' };
46	    }
47	
48	    const { error: profileError } = await supabase
49	        .from('user_profiles')
50	        .upsert(
51	            {
52	                id: user.id,
53	                customer_id: customer.customer_id,
54	                role: 'admin',
55	                created_at: new Date().toISOString(),
56	            },
57	            {
58	                onConflict: 'id',
59	                ignoreDuplicates: true,
60	            }
61	        );
62	
63	    if (profileError) {
64	        return { ok: false, reason: profileError.message };
65	    }
66	
67	    const { error: agentError } = await supabase
68	        .from('dim_agents')
69	        .insert({
70	            agent_name: 'default-agent',
71	            agent_type: 'api-key',
72	            customer_id: customer.customer_id,
73	            is_active: false,
74	            created_at: new Date().toISOString(),
75	        });
76	
77	    if (agentError) {
78	        return { ok: false, reason: agentError.message };
79	    }
80	
81	    return { ok: true };
82	}
83	
84	export async function userAuthMiddleware(c: Context, next: Next): Promise<Response | void> {
85	    const authHeader = c.req.header('Authorization');
86	    if (!authHeader?.startsWith('Bearer ')) {
87	        return c.json(
88	            { error: 'Missing or invalid Authorization header', code: 'UNAUTHORIZED' },
89	            401
90	        );
91	    }
92	
93	    const token = authHeader.slice(7);
94	
95	    // Create a per-request client with the user's JWT
96	    // so supabase.auth.getUser() validates against *their* token
97	    const userClient = createClient(SUPABASE_URL, SUPABASE_ANON_KEY, {
98	        auth: { persistSession: false, autoRefreshToken: false },
99	        global: { headers: { Authorization: `Bearer ${token}` } },
100	    });
101	
102	    const { data: { user }, error } = await userClient.auth.getUser(token);
103	
104	    if (error || !user) {
105	        return c.json(
106	            { error: 'Invalid or expired token', code: 'UNAUTHORIZED' },
107	            401
108	        );
109	    }
110	
111	    // Resolve customer_id from user_profiles (using service role client)
112	    const { data: profile, error: profileError } = await supabase
113	        .from('user_profiles')
114	        .select('customer_id, role')
115	        .eq('id', user.id)
116	        .maybeSingle();
117	
118	    if (profileError) {
119	        return c.json(
120	            {
121	                error: 'Failed to resolve account profile',
122	                code: 'PROFILE_LOOKUP_FAILED',
123	            },
124	            500
125	        );
126	    }
127	
128	    if (!profile) {
129	        // Self-heal path: if auth trigger was skipped (e.g., admin-created users),
130	        // provision a minimal account/profile/agent and retry once.
131	        const provision = await provisionMissingProfile({
132	            id: user.id,
133	            email: user.email,
134	            user_metadata: user.user_metadata,
135	        });
136	
137	        if (provision.ok) {
138	            const { data: retriedProfile, error: retryError } = await supabase
139	                .from('user_profiles')
140	                .select('customer_id, role')
141	                .eq('id', user.id)
142	                .maybeSingle();
143	
144	            if (!retryError && retriedProfile) {
145	                c.set('user_id', user.id);
146	                c.set('customer_id', retriedProfile.customer_id);
147	                await next();
148	                return;
149	            }
150	        }
151	
152	        return c.json(
153	            {
154	                error: 'Account setup incomplete',
155	                code: 'PROFILE_MISSING',
156	                action: 'Please sign out and sign in again to trigger account setup',
157	                details: provision.reason,
158	            },
159	            403
160	        );
161	    }
162	
163	    c.set('user_id', user.id);
164	    c.set('customer_id', profile.customer_id);
165	
166	    await next();
167	}
