2	 * Layerinfinite — middleware/admin-auth.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Admin authentication middleware.
5	 * Accepts either:
6	 * 1) Supabase JWT (dashboard users)
7	 * 2) Raw API key (SDK users)
8	 * ══════════════════════════════════════════════════════════════
9	 */
10	
11	import { Context, Next } from 'hono';
12	import { supabase } from '../lib/supabase.js';
13	
14	export async function adminAuthMiddleware(c: Context, next: Next): Promise<Response | void> {
15	    const customerId = c.get('customer_id') as string | undefined;
16	
17	    if (!customerId) {
18	        return c.json({ error: 'Unauthorized', code: 'UNAUTHORIZED' }, 401);
19	    }
20	
21	    const { data, error } = await supabase
22	        .from('dim_customers')
23	        .select('customer_id, config')
24	        .eq('customer_id', customerId)
25	        .maybeSingle();
26	
27	    if (error) {
28	        return c.json({ error: 'Admin auth service unavailable', code: 'AUTH_ERROR' }, 503);
29	    }
30	
31	    const role = (data as any)?.config?.role;
32	    if (role !== 'customer_admin') {
33	        return c.json({ error: 'Forbidden', code: 'FORBIDDEN' }, 403);
34	    }
35	
36	    await next();
37	}
